import sys
import functools

def main():
    N = int(sys.stdin.readline())

    @functools.lru_cache(maxsize=None)
    def cost(x):
        if x < 2:
            return 0
        return x + cost(x // 2) + cost((x + 1) // 2)

    print(cost(N))

if __name__ == "__main__":
    main()
